import { css } from '@emotion/css'
import { useThrowRandomConfetti } from '@kyokuya/react-confetti'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import { SudokuCoreActionType, SudokuCoreContextType } from '@kyokuya/react-game-sudoku-core'
import GamePausedIcon from '@mui/icons-material/PauseCircleFilled'
import GamePendingIcon from '@mui/icons-material/PlayArrow'
import GameRefreshIcon from '@mui/icons-material/Refresh'
import Button from '@mui/material/Button'
import React from 'react'

export const GameOverlay: React.FC = () => {
  const { state, dispatch } = React.useContext(SudokuCoreContextType)
  const throwConfetti = useThrowRandomConfetti()
  const classes = useStyles()

  return React.useMemo(() => {
    // Start game.
    const startGame = (): void => dispatch({ type: SudokuCoreActionType.START })

    // Resume game.
    const resumeGame = (): void => dispatch({ type: SudokuCoreActionType.RESUME })

    // Restart game.
    const restartGame = (): void => dispatch({ type: SudokuCoreActionType.RESTART })

    switch (state.gameStatus) {
      case GameRunningStatus.PENDING: {
        return (
          <div className={classes.overlay}>
            <Button
              className={classes.button}
              variant="contained"
              color="primary"
              startIcon={<GamePendingIcon />}
              onClick={startGame}
            >
              Start
            </Button>
          </div>
        )
      }
      case GameRunningStatus.PAUSED: {
        return (
          <div className={classes.overlay}>
            <Button
              className={classes.button}
              variant="contained"
              color="primary"
              startIcon={<GamePausedIcon />}
              onClick={resumeGame}
            >
              Resume
            </Button>
          </div>
        )
      }
      case GameRunningStatus.FINISHED: {
        void throwConfetti()
        return (
          <div className={classes.overlay}>
            <div className={classes.finishedBanner}>
              <p>You win 🎉🎉🎉</p>
              <Button
                className={classes.button}
                variant="contained"
                color="primary"
                startIcon={<GameRefreshIcon />}
                onClick={restartGame}
              >
                New
              </Button>
            </div>
          </div>
        )
      }
      default:
        return null
    }
  }, [classes, state.gameStatus, throwConfetti, dispatch])
}

// eslint-disable-next-line @typescript-eslint/explicit-function-return-type
const useStyles = () => {
  return React.useMemo(
    () => ({
      overlay: css`
        position: relative;
        display: flex;
        align-items: center;
        justify-content: center;
        height: 100%;
        width: 100%;
        user-select: none;
      `,
      confettiCanvas: css`
        position: absolute;
        top: 0;
        bottom: 0;
        left: 0;
        right: 0;
        width: 100%;
        height: 100%;
      `,
      button: css`
        &&, &&:hover {
          box-shadow: 4px 4px 16px 0px hsl(0deg 0% 0% / 0.75);
        }
      `,
      finishedBanner: css`
        position: relative;
        display: flex;
        flex-direction: column;
        justify-content: center;
        padding: 0;
        margin: 0;
        font-size: 32px;
      `,
      playerName: css`
        color: #e200e2;
      `,
    }),
    [],
  )
}
