import { css, cx } from '@emotion/css'
import { ElapsedTimer, GameRunningStatus } from '@kyokuya/react-game-core'
import { SudokuCoreActionType, SudokuCoreContextType } from '@kyokuya/react-game-sudoku-core'
import HintIcon from '@mui/icons-material/EmojiObjects'
import GameRunningIcon from '@mui/icons-material/Pause'
import RefreshIcon from '@mui/icons-material/Refresh'
import TimerIcon from '@mui/icons-material/Timer'
import VisibilityIcon from '@mui/icons-material/Visibility'
import { Button, Dialog, DialogActions, DialogContent, IconButton, Tooltip } from '@mui/material'
import PropTypes from 'prop-types'
import React from 'react'

export interface IGameToolbarProps {
  containerRef: React.RefObject<HTMLDivElement>
}

export const GameToolbar: React.FC<IGameToolbarProps> = props => {
  const { containerRef } = props
  const { state, dispatch } = React.useContext(SudokuCoreContextType)
  const { score, gameStatus, usedTimeRef } = state
  const [restartDialogVisible, setRestartDialogVisible] = React.useState<boolean>(false)

  const actions = React.useMemo(
    () => ({
      // Show cheat
      showCheat: (): void => {
        dispatch({ type: SudokuCoreActionType.TOGGLE_CHEAT_VISIBILITY, payload: true })
      },
      // Restart game.
      restartGame: (): void => {
        setRestartDialogVisible(false)
        dispatch({ type: SudokuCoreActionType.RESTART })
      },
      // Pause game.
      pauseGame: (): void => {
        dispatch({ type: SudokuCoreActionType.PAUSE })
      },
      hint: (): void => {
        dispatch({ type: SudokuCoreActionType.HINT })
      },
      // Update spent time.
      onUsedTimeChange: (usedTime: number): void => {
        dispatch({ type: SudokuCoreActionType.REFRESH_TIME_USED, payload: usedTime })
      },
    }),
    [dispatch],
  )

  const classes = useStyles()
  return (
    <div className={classes.toolbar}>
      <div className={cx(classes.item, classes.buttons)}>
        <Button
          variant="contained"
          color="inherit"
          startIcon={<RefreshIcon />}
          onClick={() =>
            gameStatus === GameRunningStatus.PENDING || gameStatus === GameRunningStatus.FINISHED
              ? actions.restartGame()
              : setRestartDialogVisible(true)
          }
        >
          New
        </Button>
        <Button
          variant="contained"
          color="inherit"
          disabled={gameStatus !== GameRunningStatus.RUNNING}
          startIcon={<HintIcon />}
          onClick={actions.hint}
        >
          HINT
        </Button>
        <Button
          variant="contained"
          color="secondary"
          disabled={gameStatus !== GameRunningStatus.RUNNING}
          startIcon={<VisibilityIcon />}
          onClick={actions.showCheat}
        >
          Cheat
        </Button>
      </div>
      <div className={cx(classes.item, classes.state)}>
        <div key="state-buttons" className={classes.stateButtons}>
          {gameStatus === GameRunningStatus.RUNNING && (
            <Tooltip title="Pause">
              <IconButton color="primary" onClick={actions.pauseGame}>
                <GameRunningIcon />
              </IconButton>
            </Tooltip>
          )}
        </div>
        <div key="elapsed-time" className={classes.elapsedTime}>
          <Tooltip title="Time used">
            <TimerIcon />
          </Tooltip>
          &nbsp;&nbsp;
          <ElapsedTimer
            gameStatus={gameStatus}
            initialUsedTime={usedTimeRef.current}
            onUsedTimeChange={actions.onUsedTimeChange}
          />
        </div>
        <div key="score" className={classes.score}>
          Score: {score}
        </div>
      </div>
      <Dialog
        container={containerRef.current}
        open={restartDialogVisible}
        onClose={() => setRestartDialogVisible(false)}
        aria-labelledby="confirm-to-restart"
      >
        <DialogContent>Are you sure you want to start a new game?</DialogContent>
        <DialogActions>
          <Button color="inherit" onClick={() => setRestartDialogVisible(false)}>
            Cancel
          </Button>
          <Button color="primary" onClick={actions.restartGame}>
            Confirm
          </Button>
        </DialogActions>
      </Dialog>
    </div>
  )
}

GameToolbar.propTypes = {
  containerRef: PropTypes.any.isRequired,
}

// eslint-disable-next-line @typescript-eslint/explicit-function-return-type
const useStyles = () => ({
  toolbar: css`
    display: block;
    max-width: min(90vw, 400px);
    margin: auto;
  `,
  item: css`
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    justify-content: flex-start;
    margin: 1rem 0;
    > * {
      margin-right: 1rem;
    }
  `,
  buttons: css`
    justify-content: space-around;
    > button {
      margin: 0 4px;
    }
  `,
  state: css`
    justify-content: center;
    margin: 2rem 0 0;
    height: 48px;
  `,
  stateButtons: css`
    flex: 0 1 auto;
    display: flex;
    align-items: center;
    justify-content: center;
    margin: 0;
    user-select: none;
  `,
  elapsedTime: css`
    flex: 0 1 auto;
    display: flex;
    align-items: center;
    font-family: Consolas, 'Source Code Pro', 'Roboto Mono', monospace, sans-serif;
    color: #595959;
    user-select: none;
  `,
  score: css`
    flex: 0 1 auto;
    color: green;
    overflow: hidden;
    text-overflow: ellipsis;
    font-family: Consolas, 'Source Code Pro', 'Roboto Mono', monospace, sans-serif;
  `,
})
